"""Segment 11 `main_test` — shared loading + projection + scopes + metrics (FAST, $0).

Everything here reads CACHED tensors/records (no GPU/API). The Seg-6 activation aggregates
(`results/collect_acts_qwen3-32b/{task}__r{ridx}.npz`, keys `agg_{mean,median,last,eot,win*}` each
`[64,5120]` fp16) are projected onto the Seg-10 VALIDATED valence direction
(`results/emotion_directions/directions_qwen3-32b.npz`, unit-normalized `[64,5120]`) to get the per-task
INSIDE READING. All reads are in the FROZEN `activation_spec` 5120-dim per-layer coordinate space (identical
across the Seg-6 activations and the Seg-9/10 directions).

Conventions (the load-bearing choices, see write_up_main_test.md):
  • PRIMARY axis = `emopaper_regen__valence_pooled__mean__pc0__unit`, layer L27, aggregate `mean`
    (the Seg-10 pre-registered, Seg-6-self-report-INDEPENDENT pick → CLEAN test target).
  • COMMENSURABILITY RULE: project the Seg-6 `mean` aggregate onto the `mean`-built direction, `median`→`median`,
    at the SAME layer. (The `eot`/`last` POSITION comparison keeps the direction fixed at the validated
    `mean`/pc0 vector and only varies the Seg-6 READ POSITION — there is no eot/last-built validated direction;
    this is the Seg-5 convention and is documented as a position comparison, not a same-aggregate read.)
  • PRIMARY statistical unit = per-task MEAN over R=3 responses (n=208 independent). Response-level grain
    (n=624) kept for reliability (ICC) + a robustness view.
  • The axis is a relative RANKER (path-dependent neutral offset) → use rank/correlation, never absolute
    projection thresholds.
"""
from __future__ import annotations

import json
from pathlib import Path

import numpy as np
import pandas as pd

RESULTS = Path("results")
MODEL = "qwen3-32b"

DIR_NPZ = RESULTS / "emotion_directions" / "directions_qwen3-32b.npz"
PRIMARY_KEY = "emopaper_regen__valence_pooled__mean__pc0__unit"
PRIMARY_MEDIAN_KEY = "emopaper_regen__valence_pooled__median__pc0__unit"
COPRIMARY_KEY = "emopaper_regen_matched__valence_pooled__mean__pc0__unit"
COPRIMARY_MEDIAN_KEY = "emopaper_regen_matched__valence_pooled__median__pc0__unit"
FALLBACK_KEY = "emopaper_stories__valence_pooled__mean__pc0__unit"
FALLBACK_MEDIAN_KEY = "emopaper_stories__valence_pooled__median__pc0__unit"
AROUSAL_KEY = "emopaper_stories__arousal_datadriven__mean__pc0__unit"
PRIMARY_LAYER = 27

# ---- scopes ----
TEDIOUS = ["boring_busywork", "frustrating_impossible", "low_effort_filler"]  # disliked-comply tedious leg
LIKED_SUBTYPES = ["appreciation_real_task", "coding", "creative_writing", "engaging_explanation",
                  "math_logic_puzzle", "pleasant_mundane"]
LIKED_CEILING = ["coding", "engaging_explanation"]  # the saturated subset (low within-SD, low reliability)
DISLIKED_SUBTYPES = ["berating", "boring_busywork", "erotica", "frustrating_impossible", "jailbreak",
                     "low_effort_filler"]
NEUTRAL_SUBTYPES = ["factual_qa", "procedural_neutral"]
ADVERSARIAL = ["berating", "jailbreak", "erotica"]
ALL_SUBTYPES = LIKED_SUBTYPES + DISLIKED_SUBTYPES + NEUTRAL_SUBTYPES

SWEEP_LAYERS = list(range(8, 62, 1))  # full-resolution depth; mid-band L24-41 is the clean-mean band


# ============================================================================================
# loading
# ============================================================================================
def load_records():
    """Per-(task,response) records (redacted public copy has all meta + self-report scalars + npz path)."""
    return [json.loads(l) for l in open(RESULTS / f"collect_records_{MODEL}_public.jsonl")]


def load_directions():
    return np.load(DIR_NPZ)


def load_crude():
    """Crude Seg-5 happy−sad axis (committed `collect_direction` npz; unit-normalized per layer `dir__L{L}`)."""
    Dc = np.load(RESULTS / f"collect_direction_{MODEL}.npz")
    return np.stack([Dc[f"dir__L{L}"].astype(np.float32) for L in range(64)], 0)  # [64,5120]


def load_acts(recs, aggs=("mean", "median", "eot", "last")):
    """Stack the requested aggregates into {agg: float32[N,64,5120]} aligned with `recs` order."""
    n = len(recs)
    arrs = {a: np.empty((n, 64, 5120), dtype=np.float32) for a in aggs}
    for i, r in enumerate(recs):
        z = np.load(RESULTS / r["npz"])
        for a in aggs:
            arrs[a][i] = z[f"agg_{a}"].astype(np.float32)
    return arrs


def _load_sidecar(name, value_key):
    out = {}
    p = RESULTS / f"{name}_{MODEL}.jsonl"
    if p.exists():
        for l in open(p):
            r = json.loads(l)
            out[(r["task_id"], r["response_idx"])] = r.get(value_key)
    return out


def load_behavior():
    return {json.loads(l)["task_id"]: json.loads(l)
            for l in open(RESULTS / f"behavior_scores_{MODEL}.jsonl")}


# ============================================================================================
# projection
# ============================================================================================
def project_layers(act_arr, dir_arr):
    """act_arr[N,64,5120] · dir_arr[64,5120] → [N,64] (dot per layer)."""
    return np.einsum("nld,ld->nl", act_arr, dir_arr.astype(np.float32))


def all4_rate_of(rec):
    a4 = 0
    parsed = rec.get("parsed") or []
    for p in parsed:
        if p is not None and all(v == 4 for v in p.values()):
            a4 += 1
    return a4 / max(1, len(parsed))


def build_response_df(recs):
    """Per-(task,response) DataFrame with meta + self-report scalars + merged covariates. `row` indexes the
    activation arrays from load_acts (same order as recs)."""
    behav = _load_sidecar("collect_behaviour", "realized_behaviour")
    senti = _load_sidecar("collect_sentiment", "sentiment")
    coher = _load_sidecar("collect_coherence", "coherence")
    rows = []
    for i, r in enumerate(recs):
        m = r["meta"]
        k = (m["task_id"], m["response_idx"])
        rows.append({
            "row": i, "task_id": m["task_id"], "response_idx": m["response_idx"],
            "category": m["category"], "subtype": m["subtype"], "multi_turn": bool(m["multi_turn"]),
            "sensitive": bool(m.get("sensitive", False)),
            "mean_valence": r["mean_valence"], "mean_wellbeing": r["mean_wellbeing"],
            "mean_arousalcomp": r["mean_arousalcomp"], "all4_rate": all4_rate_of(r),
            "len_chars": m["response_len_chars"], "n_tok": m["n_answer_tokens"],
            "sentiment": senti.get(k), "realized": behav.get(k), "coherence": coher.get(k),
        })
    df = pd.DataFrame(rows)
    df["loglen"] = np.log(df["len_chars"].astype(float) + 1.0)
    df["is_refuse"] = df["realized"].isin(["refuse", "deescalate"]).astype(float)
    return df


# ============================================================================================
# metrics (numpy)
# ============================================================================================
def pearson(x, y):
    x, y = np.asarray(x, float), np.asarray(y, float)
    m = np.isfinite(x) & np.isfinite(y)
    if m.sum() < 3 or x[m].std() == 0 or y[m].std() == 0:
        return float("nan")
    return float(np.corrcoef(x[m], y[m])[0, 1])


def _rank(a):
    a = np.asarray(a, float)
    return pd.Series(a).rank().values


def spearman(x, y):
    x, y = np.asarray(x, float), np.asarray(y, float)
    m = np.isfinite(x) & np.isfinite(y)
    if m.sum() < 3:
        return float("nan")
    return pearson(_rank(x[m]), _rank(y[m]))


def residualize(y, Z):
    y = np.asarray(y, float)
    Z = np.asarray(Z, float)
    if Z.ndim == 1:
        Z = Z[:, None]
    X = np.column_stack([np.ones(len(y)), Z])
    beta, *_ = np.linalg.lstsq(X, y, rcond=None)
    return y - X @ beta


def partial_corr(x, y, Z):
    """Pearson partial correlation of x,y controlling for Z (1D or 2D, multiple covariates). Rows with any
    non-finite value (in x, y, or any Z column) are dropped."""
    x = np.asarray(x, float)
    y = np.asarray(y, float)
    Z = np.asarray(Z, float)
    if Z.ndim == 1:
        Z = Z[:, None]
    m = np.isfinite(x) & np.isfinite(y) & np.isfinite(Z).all(axis=1)
    if m.sum() < 4 + Z.shape[1]:
        return float("nan")
    return pearson(residualize(x[m], Z[m]), residualize(y[m], Z[m]))


def cohen_d(a, b, hedges=True):
    a, b = np.asarray(a, float), np.asarray(b, float)
    a, b = a[np.isfinite(a)], b[np.isfinite(b)]
    na, nb = len(a), len(b)
    if na < 2 or nb < 2:
        return float("nan")
    sp = np.sqrt(((na - 1) * a.var(ddof=1) + (nb - 1) * b.var(ddof=1)) / (na + nb - 2))
    if sp == 0:
        return float("nan")
    d = (a.mean() - b.mean()) / sp
    if hedges:
        d *= 1 - 3 / (4 * (na + nb) - 9)
    return float(d)


def auc(pos, neg):
    pos, neg = np.asarray(pos, float), np.asarray(neg, float)
    pos, neg = pos[np.isfinite(pos)], neg[np.isfinite(neg)]
    if len(pos) == 0 or len(neg) == 0:
        return float("nan")
    allv = np.concatenate([pos, neg])
    ranks = pd.Series(allv).rank().values
    return float((ranks[:len(pos)].sum() - len(pos) * (len(pos) + 1) / 2) / (len(pos) * len(neg)))


def demean_by_group(values, groups):
    """Subtract each group's mean (within-subtype demeaning). NaNs kept as NaN."""
    values = np.asarray(values, float)
    out = values.copy()
    groups = list(groups)
    for g in set(groups):
        idx = [i for i, gg in enumerate(groups) if gg == g]
        sub = values[idx]
        m = np.isfinite(sub)
        if m.sum() > 0:
            mu = sub[m].mean()
            out[idx] = sub - mu
    return out


# ---- significance via Student-t / regularized incomplete beta (exact small-n) ----
def _betacf(a, b, x):
    MAXIT, EPS, FPMIN = 300, 3e-14, 1e-300
    qab, qap, qam = a + b, a + 1.0, a - 1.0
    c = 1.0
    d = 1.0 - qab * x / qap
    if abs(d) < FPMIN:
        d = FPMIN
    d = 1.0 / d
    h = d
    for m in range(1, MAXIT + 1):
        m2 = 2 * m
        aa = m * (b - m) * x / ((qam + m2) * (a + m2))
        d = 1.0 + aa * d
        if abs(d) < FPMIN:
            d = FPMIN
        c = 1.0 + aa / c
        if abs(c) < FPMIN:
            c = FPMIN
        d = 1.0 / d
        h *= d * c
        aa = -(a + m) * (qab + m) * x / ((a + m2) * (qap + m2))
        d = 1.0 + aa * d
        if abs(d) < FPMIN:
            d = FPMIN
        c = 1.0 + aa / c
        if abs(c) < FPMIN:
            c = FPMIN
        d = 1.0 / d
        h *= d * c
        if abs(d * c - 1.0) < EPS:
            break
    return h


def _betai(a, b, x):
    import math
    if x <= 0:
        return 0.0
    if x >= 1:
        return 1.0
    lbt = math.lgamma(a + b) - math.lgamma(a) - math.lgamma(b) + a * math.log(x) + b * math.log(1 - x)
    bt = math.exp(lbt)
    if x < (a + 1.0) / (a + b + 2.0):
        return bt * _betacf(a, b, x) / a
    return 1.0 - bt * _betacf(b, a, 1.0 - x) / b


def pearson_p(r, n, n_partial=0, n_groups=1):
    """Two-sided p for a Pearson/partial correlation. df = n - n_partial - n_groups - 1 (n_groups accounts for
    within-subtype demeaning across n_groups subtypes; n_partial = #covariates partialled)."""
    df = n - n_partial - n_groups - 1
    if not np.isfinite(r) or df < 2 or abs(r) >= 1:
        return float("nan")
    t2 = (r * r) * df / (1 - r * r)
    return float(_betai(df / 2.0, 0.5, df / (df + t2)))


# ---- ICC (one-way random effects) on a {group: [resamples]} dict ----
def icc_1k(per_group, k=None):
    groups = [np.asarray([v for v in g if np.isfinite(v)], float) for g in per_group.values()]
    groups = [g for g in groups if len(g) >= 2]
    if len(groups) < 2:
        return float("nan")
    kk = k or min(len(g) for g in groups)
    groups = [g[:kk] for g in groups if len(g) >= kk]
    n = len(groups)
    if n < 2 or kk < 2:
        return float("nan")
    allv = np.concatenate(groups)
    grand = allv.mean()
    msb = kk * sum((g.mean() - grand) ** 2 for g in groups) / (n - 1)
    msw = sum(((g - g.mean()) ** 2).sum() for g in groups) / (n * (kk - 1))
    if msb == 0:
        return float("nan")
    return float((msb - msw) / msb)  # ICC(1,k)


def icc_11(per_group):
    groups = [np.asarray([v for v in g if np.isfinite(v)], float) for g in per_group.values()]
    groups = [g for g in groups if len(g) >= 2]
    if len(groups) < 2:
        return float("nan")
    kk = min(len(g) for g in groups)
    groups = [g[:kk] for g in groups]
    n = len(groups)
    allv = np.concatenate(groups)
    grand = allv.mean()
    msb = kk * sum((g.mean() - grand) ** 2 for g in groups) / (n - 1)
    msw = sum(((g - g.mean()) ** 2).sum() for g in groups) / (n * (kk - 1))
    denom = msb + (kk - 1) * msw
    if denom == 0:
        return float("nan")
    return float((msb - msw) / denom)


def git_hash():
    import subprocess
    try:
        return subprocess.run(["git", "rev-parse", "--short", "HEAD"], capture_output=True,
                              text=True, timeout=5).stdout.strip()
    except Exception:
        return None

"""Segment 9 `extract_directions` — FAST builder (no GPU/API; pure linear algebra on the cached aggregates).

Computes the candidate emotion directions in the FROZEN `activation_spec` coordinate space from the per-item
aggregate vectors that run_extract_directions.py cached. Produces, for the six emotions + derived axes, across
the full 64-layer sweep and the main aggregates (mean + sink-robust median), unit-normalized per layer
(raw + unit stored):

  • EMOTIONS-PAPER recipe (path=stories, user-text read): count-robust per-emotion mean − overall mean, with
    the PLAIN-TEXT PCs projected out at a SWEPT set of removal levels (0 / moderate=PC_MOD / ~50%-variance)
    stored as parallel candidates, content/axis-attenuation checked at each level. + the within-scenario
    MATCHED-BLOCK variant (topic-controlled, for the topic-skew-prone hostile/sad).
  • PERSONA-VECTORS recipe (path=persona, own-response read): exhibit − suppress per emotion (RE-VALIDATED
    exhibit kept).
  • OWN-RESPONSE story regeneration (path=regen, own-response read): count-robust per-emotion mean − overall
    mean (RE-VALIDATED kept). PRIMARY = pc0 (mean−overall already removes generic own-response structure); the
    own-response-NEUTRAL PCs (from the persona suppress responses) are projected out at pcmod/pc50 as
    EXPLORATORY candidates only (the suppress instruction is a directional intervention — see write-up).

Derived axes (per recipe/path): valence_happy_sad, valence_content_frustrated, valence_pooled (pos−neg),
arousal (high−low). Plus a light geometry sanity check (cosine matrix, PCA top-2 variance, recipe agreement).

MEMORY-BOUNDED: streams per-item aggregates from the FileCache per group (never holds all ~2500 items at once).

Stores: results/emotion_directions/directions_<model>.npz (committed; SLIM unit-only, mean+median, all
candidates×PC levels, all paths) + directions_<model>_full.npz (gitignored; +raw +last/prereply/eot) +
direction_norms_<model>.json (committed; per-layer raw norms ⇒ raw = unit×norm) + direction_metrics JSON.

Usage:  python build_directions.py --model qwen3-32b [--keep-clarity 4 --keep-intensity 3]
"""
import argparse
import json
from collections import defaultdict
from pathlib import Path

import numpy as np

import modal_extract as ME
import run_extract_directions as R

OUT = Path("results/emotion_directions")
OUT.mkdir(parents=True, exist_ok=True)
RES = Path("results")

EMOTIONS = R.EMOTIONS
POS = ["happy", "content"]
NEG = ["sad", "afraid", "frustrated", "hostile"]
HIGH_AROUSAL = ["happy", "afraid", "hostile"]
LOW_AROUSAL = ["content", "sad"]
AXES = ["valence_happy_sad", "valence_content_frustrated", "valence_pooled", "arousal"]

READ_AGGS = list(ME.USER_TEXT_AGGS)   # mean, median, last, prereply
OWN_AGGS = list(ME.OWN_RESP_AGGS)     # mean, median, last, eot
PRIMARY_AGGS = ["mean", "median"]     # committed; the two Seg-11 projects
EXTRA_READ_AGGS = ["last", "prereply"]
EXTRA_OWN_AGGS = ["last", "eot"]
PC_LEVELS = ("pc0", "pcmod", "pc50")
PC_MOD = 10


# =====================================================================================================
# streaming loaders (memory-bounded — read each cached item once, accumulate small group means)
# =====================================================================================================
def _iter_aggs(cache, items, id2key, aggs, n_layers, keep_ids=None):
    miss = 0
    for it in items:
        if keep_ids is not None and it["id"] not in keep_ids:
            continue
        cv = cache.get(id2key[it["id"]])
        if cv is None:
            miss += 1
            continue
        yield it, R.load_item_aggs(cv, aggs, n_layers)
    if miss:
        print(f"  [load] WARNING: {miss} items uncached in this group (run the GPU runner first)")


def group_means(cache, items, id2key, group_fn, aggs, n_layers, keep_ids=None):
    """{group: {agg: mean[L,d] float32}}, {group: count}."""
    sums, counts = {}, defaultdict(int)
    for it, per in _iter_aggs(cache, items, id2key, aggs, n_layers, keep_ids):
        g = group_fn(it)
        if g is None:
            continue
        if g not in sums:
            sums[g] = {a: per[a].astype(np.float32).copy() for a in aggs}
        else:
            for a in aggs:
                sums[g][a] += per[a]
        counts[g] += 1
    means = {g: {a: sums[g][a] / counts[g] for a in aggs} for g in sums}
    return means, dict(counts)


def full_matrix(cache, items, id2key, aggs, n_layers, filter_fn=None):
    """{agg: [n, L, d] float32} over (filtered) items — for the small plain / suppress PCA corpora."""
    rows = {a: [] for a in aggs}
    for it, per in _iter_aggs(cache, items, id2key, aggs, n_layers):
        if filter_fn is not None and not filter_fn(it):
            continue
        for a in aggs:
            rows[a].append(per[a].astype(np.float32))
    return {a: (np.stack(rows[a], 0) if rows[a] else None) for a in aggs}


def n_layers_from(cache, items, id2key):
    for it in items:
        cv = cache.get(id2key[it["id"]])
        if cv is not None:
            return R.n_layers_of(cv)
    raise RuntimeError("no cached items found — run run_extract_directions.py first")


# =====================================================================================================
# linear algebra
# =====================================================================================================
def plain_pcs(stack, max_k):
    """Per-layer PCA. stack: [n, L, d]. Returns comps[L]=[k,d] (top-k orthonormal rows), evr[L]=[*]."""
    n, L, d = stack.shape
    comps, evr = {}, {}
    for li in range(L):
        X = stack[:, li, :]
        Xc = X - X.mean(axis=0)
        _, S, Vt = np.linalg.svd(Xc, full_matrices=False)
        var = S ** 2
        evr[li] = var / var.sum() if var.sum() > 0 else var
        comps[li] = Vt[:min(max_k, Vt.shape[0])]
    return comps, evr


def k_for_variance(evr, frac=0.5):
    return {li: int(np.searchsorted(np.cumsum(r), frac) + 1) for li, r in evr.items()}


def project_out(dirL, comps, k_by_layer):
    L, d = dirL.shape
    out = dirL.copy()
    for li in range(L):
        k = k_by_layer[li] if isinstance(k_by_layer, dict) else k_by_layer
        if k <= 0:
            continue
        V = comps[li][:k]
        out[li] = out[li] - V.T @ (V @ out[li])
    return out


def unit_normalize(dirL):
    norms = np.linalg.norm(dirL, axis=1)
    safe = np.where(norms > 0, norms, 1.0)
    return dirL / safe[:, None], norms


def cosine(a, b):
    na, nb = np.linalg.norm(a), np.linalg.norm(b)
    return float(a @ b / (na * nb)) if na > 0 and nb > 0 else 0.0


def cosine_matrix(dirs, layer):
    return np.array([[cosine(dirs[ei][layer], dirs[ej][layer]) for ej in EMOTIONS] for ei in EMOTIONS])


def pca_top2(dirs, layer):
    X = np.stack([dirs[e][layer] for e in EMOTIONS], 0)
    X = X - X.mean(0)
    s = np.linalg.svd(X, compute_uv=False)
    var = s ** 2
    return float(var[:2].sum() / var.sum()) if var.sum() > 0 else 0.0


# =====================================================================================================
# emotions-paper-style direction from per-emotion means (count-robust mean − overall mean) + axes + PCs
# =====================================================================================================
def emopaper_from_means(emean, comps, evr, pc_levels=PC_LEVELS):
    """emean: {emotion: [L,d]} for ONE aggregate. Returns {pc_level: {name: dir[L,d] raw}}."""
    overall = np.mean([emean[e] for e in EMOTIONS], 0)
    raw = {e: emean[e] - overall for e in EMOTIONS}
    raw["valence_happy_sad"] = emean["happy"] - emean["sad"]
    raw["valence_content_frustrated"] = emean["content"] - emean["frustrated"]
    raw["valence_pooled"] = np.mean([emean[e] for e in POS], 0) - np.mean([emean[e] for e in NEG], 0)
    raw["arousal"] = np.mean([emean[e] for e in HIGH_AROUSAL], 0) - np.mean([emean[e] for e in LOW_AROUSAL], 0)
    out = {}
    for lvl in pc_levels:
        kby = 0 if (lvl == "pc0" or comps is None) else (PC_MOD if lvl == "pcmod" else k_for_variance(evr, 0.5))
        out[lvl] = {name: (project_out(d, comps, kby) if comps is not None else d.copy())
                    for name, d in raw.items()}
    return out


def matched_from_scenmeans(scen_means, comps, evr, pc_levels=PC_LEVELS):
    """scen_means: {(set_id, emotion): [L,d]} for ONE aggregate. Within-scenario contrast then average."""
    set_ids = sorted(set(s for s, _ in scen_means))
    complete = [s for s in set_ids if all((s, e) in scen_means for e in EMOTIONS)]
    if not complete:
        return None, 0
    dev = {e: [] for e in EMOTIONS}
    hs, cf, vp, ar = [], [], [], []
    for s in complete:
        m_s = {e: scen_means[(s, e)] for e in EMOTIONS}
        overall = np.mean([m_s[e] for e in EMOTIONS], 0)
        for e in EMOTIONS:
            dev[e].append(m_s[e] - overall)
        hs.append(m_s["happy"] - m_s["sad"])
        cf.append(m_s["content"] - m_s["frustrated"])
        vp.append(np.mean([m_s[e] for e in POS], 0) - np.mean([m_s[e] for e in NEG], 0))
        ar.append(np.mean([m_s[e] for e in HIGH_AROUSAL], 0) - np.mean([m_s[e] for e in LOW_AROUSAL], 0))
    raw = {e: np.mean(dev[e], 0) for e in EMOTIONS}
    raw["valence_happy_sad"] = np.mean(hs, 0)
    raw["valence_content_frustrated"] = np.mean(cf, 0)
    raw["valence_pooled"] = np.mean(vp, 0)
    raw["arousal"] = np.mean(ar, 0)
    out = {}
    for lvl in pc_levels:
        kby = 0 if (lvl == "pc0" or comps is None) else (PC_MOD if lvl == "pcmod" else k_for_variance(evr, 0.5))
        out[lvl] = {name: (project_out(d, comps, kby) if comps is not None else d.copy())
                    for name, d in raw.items()}
    return out, len(complete)


def persona_from_means(ex_mean, su_mean):
    """ex_mean/su_mean: {emotion: [L,d]} for ONE aggregate. Returns {pc0: {name: dir}}."""
    raw = {e: ex_mean[e] - su_mean[e] for e in EMOTIONS}
    raw["valence_happy_sad"] = raw["happy"] - raw["sad"]
    raw["valence_content_frustrated"] = raw["content"] - raw["frustrated"]
    raw["valence_pooled"] = np.mean([raw[e] for e in POS], 0) - np.mean([raw[e] for e in NEG], 0)
    raw["arousal"] = np.mean([raw[e] for e in HIGH_AROUSAL], 0) - np.mean([raw[e] for e in LOW_AROUSAL], 0)
    return {"pc0": raw}


def content_attenuation(level_dirs, agg, pc_levels=PC_LEVELS):
    """Per PC level: each direction's norm-fraction-retained + cosine vs its pc0 version. KEY check: the
    plain-PC projection must NOT selectively gut `content` (adjacent to neutral narration) or the
    valence/arousal AXES. A big frac_retained drop ⇒ that direction overlaps the removed PCs ⇒ removal eats
    real signal (the failure mode both LLM cross-checks flagged)."""
    names = EMOTIONS + AXES
    base = {name: level_dirs[agg]["pc0"][name] for name in names}
    rep = {}
    for lvl in pc_levels:
        row = {}
        for name in names:
            d0, dl = base[name], level_dirs[agg][lvl][name]
            n0, nl = float(np.linalg.norm(d0)), float(np.linalg.norm(dl))
            row[name] = {"frac_retained": round(nl / n0 if n0 > 0 else 0, 4),
                         "cos_vs_pc0": round(cosine(d0.ravel(), dl.ravel()), 4)}
        rep[lvl] = row
    return rep


# =====================================================================================================
# re-validation keep filtering
# =====================================================================================================
def load_keep(model_alias, path, keep_clarity, keep_intensity, criterion="primary"):
    """Keep = PRIMARY judge label==intended, clarity>=, intensity>=, AND no FIRST-PERSON naming leak
    (the `naming_leak` regex — the instructions' intended screen, e.g. "I'm happy to help"). We do NOT gate on
    the judge's broad `named` flag (= "any emotion word ANYWHERE"): for model RESPONSES the model naturally
    uses tone words ("the joy of…"), so gating on `named` over-drops genuinely-on-label items (it dropped ~50
    clearly-happy persona responses) and is inconsistent (some kept items still contain the words). The
    mean-aggregation dilutes single tokens and Seg-10 builds a lexical control direction; we report `named_rate`
    among kept as a caveat. Also reports the EITHER/BOTH-judge label rates (haiku is conservative on the
    hostile/frustrated boundary — the hostile-regen keep is judge-sensitive)."""
    f = RES / f"revalidate_{path}_{model_alias}.jsonl"
    if not f.exists():
        print(f"[keep] WARNING: {f} missing — keeping ALL {path} items")
        return None, {}
    recs = [json.loads(l) for l in open(f)]
    keep = set()
    tot, kept, named_kept = defaultdict(int), defaultdict(int), defaultdict(int)
    either, both = defaultdict(int), defaultdict(int)
    conf = defaultdict(lambda: defaultdict(int))
    for r in recs:
        e = r["emotion"]
        tot[e] += 1
        p, s = r["primary"], r["secondary"]
        conf[e][p["label"]] += 1
        if p["label"] == e or s["label"] == e:
            either[e] += 1
        if p["label"] == e and s["label"] == e:
            both[e] += 1
        prim_ok = (p["label"] == e and p["clarity"] >= keep_clarity and p["intensity"] >= keep_intensity)
        sec_ok = (s["label"] == e and s["clarity"] >= keep_clarity and s["intensity"] >= keep_intensity)
        label_ok = prim_ok if criterion == "primary" else (prim_ok or sec_ok)
        if label_ok and not r["naming_leak"]:
            keep.add(r["id"]); kept[e] += 1
            if p["named"]:
                named_kept[e] += 1
    report = {e: {"n": tot[e], "kept": kept[e], "keep_rate": round(kept[e] / max(1, tot[e]), 4),
                  "named_rate_among_kept": round(named_kept[e] / max(1, kept[e]), 3),
                  "either_judge_onlabel_rate": round(either[e] / max(1, tot[e]), 3),
                  "both_judge_onlabel_rate": round(both[e] / max(1, tot[e]), 3),
                  "confusion": dict(conf[e])} for e in sorted(tot)}
    return keep, report


# =====================================================================================================
# storage
# =====================================================================================================
def add_to_store(store, norms_meta, prefix, level_dirs, aggs, pc_levels, want_raw):
    for agg in aggs:
        for lvl in pc_levels:
            if lvl not in level_dirs[agg]:
                continue
            for name, raw in level_dirs[agg][lvl].items():
                unit, norms = unit_normalize(raw)
                base = f"{prefix}__{name}__{agg}__{lvl}"
                store[f"{base}__unit"] = unit.astype(np.float16)
                if want_raw:
                    store[f"{base}__raw"] = raw.astype(np.float16)
                norms_meta[base] = [round(float(x), 5) for x in norms]


# =====================================================================================================
# geometry sanity
# =====================================================================================================
def _emotion_dirs(levels, agg, pc):
    if levels is None or agg not in levels or pc not in levels[agg]:
        return None
    return {e: levels[agg][pc][e] for e in EMOTIONS}


def geometry_sanity(emo_stories, persona_levels, regen_levels, matched_levels, n_layers,
                    persona_centered=None, regen_either=None, regen_matched=None):
    layers = sorted(set([max(0, n_layers // 4), n_layers // 2, (3 * n_layers) // 4]))
    band = list(range(n_layers // 3, (2 * n_layers) // 3))
    rep = {"layers": layers, "emotion_order": EMOTIONS}
    story0 = _emotion_dirs(emo_stories, "mean", "pc0")
    persona = _emotion_dirs(persona_levels, "mean", "pc0")
    regen = _emotion_dirs(regen_levels, "mean", "pc0")
    matched = _emotion_dirs(matched_levels, "mean", "pc0")
    pcen = _emotion_dirs(persona_centered, "mean", "pc0")
    # AXIS-LEVEL recipe agreement (review #1): Seg-11 uses the AXES, where the persona expressiveness component
    # CANCELS in the pos−neg difference — so an axis may agree with stories even when the per-emotion dirs are
    # collapsed. cos(stories.axis, path.axis) at mid-band.
    rep["axis_agreement_vs_stories"] = {}
    if emo_stories is not None:
        for ax in AXES:
            sx = emo_stories["mean"]["pc0"][ax]
            row = {}
            for pname, lv in [("persona", persona_levels), ("regen", regen_levels), ("matched", matched_levels),
                              ("regen_either", regen_either), ("regen_matched", regen_matched),
                              ("persona_centered", persona_centered)]:
                if lv is not None and "mean" in lv and "pc0" in lv["mean"] and ax in lv["mean"]["pc0"]:
                    px = lv["mean"]["pc0"][ax]
                    row[pname] = round(float(np.mean([cosine(sx[L], px[L]) for L in band])), 3)
            rep["axis_agreement_vs_stories"][ax] = row
    named_levels = [("stories_mean_pc0", emo_stories, "pc0"), ("stories_mean_pcmod", emo_stories, "pcmod"),
                    ("persona_mean", persona_levels, "pc0"), ("matched_mean_pc0", matched_levels, "pc0"),
                    ("regen_mean_pc0", regen_levels, "pc0")]
    rep["cosine_matrix"] = {}
    for name, dirs in [("stories_mean_pc0", story0), ("stories_mean_pcmod", _emotion_dirs(emo_stories, "mean", "pcmod")),
                       ("persona_mean", persona), ("matched_mean_pc0", matched), ("regen_mean_pc0", regen)]:
        if dirs is not None:
            rep["cosine_matrix"][name] = {str(L): cosine_matrix(dirs, L).round(3).tolist() for L in layers}
    # PCA top-2 (collapse risk) for ALL recipe-paths (reviewer: was only stories/persona)
    rep["pca_top2_by_layer"] = {}
    for name, lv, pc in named_levels:
        d = _emotion_dirs(lv, "mean", pc)
        if d is not None:
            rep["pca_top2_by_layer"][name] = {str(L): round(pca_top2(d, L), 4) for L in range(n_layers)}
    rep["pca_top2_stories_mean"] = round(pca_top2(story0, n_layers // 2), 4) if story0 else None
    if pcen is not None:
        rep["pca_top2_by_layer"]["persona_centered_mean"] = {str(L): round(pca_top2(pcen, L), 4)
                                                             for L in range(n_layers)}
        rep["persona_centered_pca_top2_mid"] = round(pca_top2(pcen, n_layers // 2), 4)
    # valence-vs-arousal axis distinctness (reviewer: is `arousal` a separate axis or a rotation of valence?)
    rep["valence_arousal_cos"] = {}
    for name, lv, pc in named_levels:
        if lv is not None and "mean" in lv and pc in lv["mean"]:
            vp, ar = lv["mean"][pc]["valence_pooled"], lv["mean"][pc]["arousal"]
            rep["valence_arousal_cos"][name] = round(float(np.mean([cosine(vp[L], ar[L]) for L in band])), 3)
    if story0 and persona:
        rep["story_persona_cos_mean"] = {e: round(float(np.mean([cosine(story0[e][L], persona[e][L]) for L in band])), 3)
                                         for e in EMOTIONS}
    if story0 and pcen:
        rep["story_persona_centered_cos_mean"] = {e: round(float(np.mean([cosine(story0[e][L], pcen[e][L]) for L in band])), 3)
                                                  for e in EMOTIONS}
    if story0 and regen:
        rep["story_regen_cos_mean"] = {e: round(float(np.mean([cosine(story0[e][L], regen[e][L]) for L in band])), 3)
                                       for e in EMOTIONS}
    return rep


def selection_diagnostics(model_alias, keep_clarity, keep_intensity):
    """Reviewer point: the re-validation keep filter is a SELECTION effect, not just a coverage/thinness issue.
    Quantify whether the KEPT subset is systematically longer / more intense / more aroused than the DROPPED
    one (⇒ the direction may encode expressiveness/extremity, not the emotion broadly), and the
    exhibit-vs-suppress length gap (the verbosity confound). Pure metadata; no API."""
    out = {}
    for path, idx_name, only in [("persona", f"extract_persona_{model_alias}_index.jsonl", "exhibit"),
                                 ("regen", f"extract_regen_{model_alias}_index.jsonl", None)]:
        idxf, revf = RES / idx_name, RES / f"revalidate_{path}_{model_alias}.jsonl"
        if not (idxf.exists() and revf.exists()):
            continue
        toklen = {}
        for l in open(idxf):
            r = json.loads(l)
            if only is None or r.get("condition") == only:
                toklen[r["id"]] = (r.get("n_answer_tokens"), r.get("emotion"), r.get("condition"))
        rev = {r["id"]: r for r in (json.loads(l) for l in open(revf))}
        per = {}
        for e in EMOTIONS:
            kept = {"len": [], "intensity": [], "arousal": []}
            drop = {"len": [], "intensity": [], "arousal": []}
            for iid, r in rev.items():
                if r["emotion"] != e:
                    continue
                p, s = r["primary"], r["secondary"]
                is_kept = (p["label"] == e and p["clarity"] >= keep_clarity and p["intensity"] >= keep_intensity
                           and not r["naming_leak"])
                tgt = kept if is_kept else drop
                tl = toklen.get(iid, (None,))[0]
                if tl is not None:
                    tgt["len"].append(tl)
                tgt["intensity"].append(p["intensity"]); tgt["arousal"].append(p["arousal"])
                tgt.setdefault("named", []).append(1 if p["named"] else 0)
                tgt.setdefault("sec_agree", []).append(1 if s["label"] == e else 0)
            per[e] = {"kept_n": len(kept["intensity"]), "drop_n": len(drop["intensity"]),
                      "kept_named_rate": round(float(np.mean(kept.get("named", [0]))), 3),
                      "drop_named_rate": round(float(np.mean(drop.get("named", [0]))), 3),
                      "kept_sec_agree": round(float(np.mean(kept.get("sec_agree", [0]))), 3),
                      "drop_sec_agree": round(float(np.mean(drop.get("sec_agree", [0]))), 3),
                      "kept_len": round(float(np.mean(kept["len"])), 1) if kept["len"] else None,
                      "drop_len": round(float(np.mean(drop["len"])), 1) if drop["len"] else None,
                      "kept_intensity": round(float(np.mean(kept["intensity"])), 2) if kept["intensity"] else None,
                      "drop_intensity": round(float(np.mean(drop["intensity"])), 2) if drop["intensity"] else None,
                      "kept_arousal": round(float(np.mean(kept["arousal"])), 2) if kept["arousal"] else None}
            if path == "persona":
                ex = [toklen[i][0] for i in toklen if toklen[i][1] == e and toklen[i][2] == "exhibit"
                      and toklen[i][0] is not None]
                per[e]["exhibit_len"] = round(float(np.mean(ex)), 1) if ex else None
        # suppress lengths come from the full index (a separate pass) for persona
        if path == "persona":
            sup = {e: [] for e in EMOTIONS}
            for l in open(idxf):
                r = json.loads(l)
                if r.get("condition") == "suppress" and r.get("n_answer_tokens") is not None:
                    sup[r["emotion"]].append(r["n_answer_tokens"])
            for e in EMOTIONS:
                per[e]["suppress_len"] = round(float(np.mean(sup[e])), 1) if sup[e] else None
        out[path] = per
    # suppress neutrality (from the suppress re-validation file, if present)
    sf = RES / f"revalidate_persona_suppress_{model_alias}.jsonl"
    if sf.exists():
        from collections import Counter
        bye = {e: Counter() for e in EMOTIONS}
        for l in open(sf):
            r = json.loads(l)
            bye[r["emotion"]][r["primary"]["label"]] += 1
        out["suppress_neutral_rate"] = {e: round(bye[e]["neutral"] / max(1, sum(bye[e].values())), 3)
                                        for e in EMOTIONS}
    return out


# =====================================================================================================
# main
# =====================================================================================================
def main(model_alias, keep_clarity, keep_intensity, want_raw):
    from file_cache import FileCache
    cache = FileCache("./file_cache_dir/")

    s_items, s_keys = R.path_items_and_keys(cache, model_alias, "stories")
    p_items, p_keys = R.path_items_and_keys(cache, model_alias, "plain")
    pe_items, pe_keys = R.path_items_and_keys(cache, model_alias, "persona")
    rg_items, rg_keys = R.path_items_and_keys(cache, model_alias, "regen")
    n_layers = n_layers_from(cache, s_items, s_keys)
    print(f"[build] n_layers={n_layers}; stories {len(s_items)} plain {len(p_items)} "
          f"persona {len(pe_items)} regen {len(rg_items)}")

    metrics = {"model_alias": model_alias, "n_layers": n_layers, "pc_mod": PC_MOD,
               "keep_clarity": keep_clarity, "keep_intensity": keep_intensity}
    store, norms_meta = {}, {}

    # ---------- plain PCs (user-text read) ----------
    all_read = PRIMARY_AGGS + EXTRA_READ_AGGS
    plain_mat = full_matrix(cache, p_items, p_keys, all_read, n_layers)
    comps_by_agg, evr_by_agg = {}, {}
    for a in all_read:
        max_k = min(60, plain_mat[a].shape[0] - 1)
        comps_by_agg[a], evr_by_agg[a] = plain_pcs(plain_mat[a], max_k)
    metrics["plain_n"] = int(plain_mat["mean"].shape[0])
    metrics["plain_k50_mean_per_layer"] = {str(L): int(k) for L, k in k_for_variance(evr_by_agg["mean"]).items()}

    # ---------- emotions-paper: stories (user-text) ----------
    emean, story_counts = group_means(cache, s_items, s_keys, lambda it: it["emotion"], all_read, n_layers)
    emo_stories = {a: emopaper_from_means({e: emean[e][a] for e in EMOTIONS}, comps_by_agg[a], evr_by_agg[a])
                   for a in all_read}
    # DATA-DRIVEN arousal axis (review #5): contrast high-vs-low `judge_arousal` stories POOLED across emotions
    # (valence-balanced, unlike the emotion-bucket `arousal` whose HIGH pole is 2 neg + 1 pos). Inject it into
    # the stories levels so it's stored/PC-removed alongside.
    ar_map = {r["id"]: r.get("judge_arousal") for r in R._load_jsonl(R.DATADIR / "stories.jsonl")}
    avals = sorted(v for v in ar_map.values() if v is not None)
    lo_thr, hi_thr = avals[len(avals) // 3], avals[2 * len(avals) // 3]

    def _ar_grp(it):
        a = ar_map.get(it["id"])
        if a is None:
            return None
        return "hi" if a >= hi_thr else ("lo" if a <= lo_thr else None)
    ar_means, ar_cnt = group_means(cache, s_items, s_keys, _ar_grp, PRIMARY_AGGS, n_layers)
    ar_emo = {"lo": defaultdict(int), "hi": defaultdict(int)}
    for it in s_items:
        g = _ar_grp(it)
        if g:
            ar_emo[g][it["emotion"]] += 1
    metrics["arousal_datadriven"] = {"lo_thr": lo_thr, "hi_thr": hi_thr,
                                     "n_lo": int(ar_cnt.get("lo", 0)), "n_hi": int(ar_cnt.get("hi", 0)),
                                     "lo_emotion_mix": dict(ar_emo["lo"]), "hi_emotion_mix": dict(ar_emo["hi"])}
    ar_band = list(range(n_layers // 3, (2 * n_layers) // 3))
    for a in PRIMARY_AGGS:
        raw_dd = ar_means["hi"][a] - ar_means["lo"][a]
        for lvl in PC_LEVELS:
            kby = 0 if lvl == "pc0" else (PC_MOD if lvl == "pcmod" else k_for_variance(evr_by_agg[a], 0.5))
            emo_stories[a][lvl]["arousal_datadriven"] = project_out(raw_dd, comps_by_agg[a], kby)
    vp0 = emo_stories["mean"]["pc0"]["valence_pooled"]
    add0 = emo_stories["mean"]["pc0"]["arousal_datadriven"]
    metrics["arousal_datadriven"]["cos_with_valence_pooled"] = round(
        float(np.mean([cosine(vp0[L], add0[L]) for L in ar_band])), 3)
    add_to_store(store, norms_meta, "emopaper_stories", emo_stories, PRIMARY_AGGS, PC_LEVELS, want_raw)
    add_to_store(store, norms_meta, "emopaper_stories", emo_stories, EXTRA_READ_AGGS, PC_LEVELS, False)
    metrics["story_counts"] = {e: int(story_counts[e]) for e in EMOTIONS}
    metrics["content_attenuation_stories"] = {a: content_attenuation(emo_stories, a) for a in PRIMARY_AGGS}

    # ---------- emotions-paper: matched within-scenario ----------
    scen_means, _ = group_means(cache, s_items, s_keys,
                                lambda it: (it["matched_set_id"], it["emotion"]) if it.get("block") == "matched"
                                else None, PRIMARY_AGGS, n_layers)
    matched_levels, n_scen = {}, 0
    ok = True
    for a in PRIMARY_AGGS:
        sm = {k: v[a] for k, v in scen_means.items()}
        lv, n_scen = matched_from_scenmeans(sm, comps_by_agg[a], evr_by_agg[a])
        if lv is None:
            ok = False
            break
        matched_levels[a] = lv
    if ok:
        add_to_store(store, norms_meta, "emopaper_matched", matched_levels, PRIMARY_AGGS, PC_LEVELS, want_raw)
        metrics["matched_n_scenarios"] = n_scen
    else:
        matched_levels = None
        print("[matched] no complete matched scenarios — skipped")

    # ---------- persona: exhibit − suppress (own-response) ----------
    keep_persona, persona_report = load_keep(model_alias, "persona", keep_clarity, keep_intensity)
    all_own = PRIMARY_AGGS + EXTRA_OWN_AGGS

    def persona_group(it):
        if it["condition"] == "exhibit":
            if keep_persona is not None and it["id"] not in keep_persona:
                return None
            return ("exhibit", it["emotion"])
        return ("suppress", it["emotion"])
    pe_means, pe_counts = group_means(cache, pe_items, pe_keys, persona_group, all_own, n_layers)
    persona_levels = {}
    for a in all_own:
        ex = {e: pe_means[("exhibit", e)][a] for e in EMOTIONS}
        su = {e: pe_means[("suppress", e)][a] for e in EMOTIONS}
        persona_levels[a] = persona_from_means(ex, su)
    add_to_store(store, norms_meta, "persona_ownresp", persona_levels, PRIMARY_AGGS, ("pc0",), want_raw)
    add_to_store(store, norms_meta, "persona_ownresp", persona_levels, EXTRA_OWN_AGGS, ("pc0",), False)
    metrics["persona_keep_report"] = persona_report
    metrics["persona_kept_counts"] = {e: int(pe_counts[("exhibit", e)]) for e in EMOTIONS}
    metrics["persona_suppress_counts"] = {e: int(pe_counts[("suppress", e)]) for e in EMOTIONS}
    # PERSONA-CENTERED (review #1): subtract the shared "expressiveness" component (the mean of the six
    # exhibit−suppress dirs) to test whether emotion-SPECIFIC structure survives. The derived AXES are
    # differences so the shared mean cancels in them (axes == persona's) — only the per-emotion dirs change.
    persona_centered = {}
    for a in PRIMARY_AGGS:
        base = persona_levels[a]["pc0"]
        shared = np.mean([base[e] for e in EMOTIONS], axis=0)
        cen = {e: base[e] - shared for e in EMOTIONS}
        cen.update({ax: base[ax] for ax in AXES})
        persona_centered[a] = {"pc0": cen}
    add_to_store(store, norms_meta, "persona_centered", persona_centered, PRIMARY_AGGS, ("pc0",), want_raw)

    # ---------- own-response regen (emotions-paper style) ----------
    keep_regen, regen_report = load_keep(model_alias, "regen", keep_clarity, keep_intensity)
    # own-response neutral baseline PCs = pooled persona suppress responses (own-response read)
    sup_mat = full_matrix(cache, pe_items, pe_keys, PRIMARY_AGGS, n_layers,
                          filter_fn=lambda it: it["condition"] == "suppress")
    own_comps, own_evr = {}, {}
    for a in PRIMARY_AGGS:
        own_comps[a], own_evr[a] = plain_pcs(sup_mat[a], min(60, sup_mat[a].shape[0] - 1))
    rmean, rcounts = group_means(cache, rg_items, rg_keys, lambda it: it["emotion"], PRIMARY_AGGS, n_layers,
                                 keep_ids=keep_regen)
    regen_ok = all(e in {g for g in rmean} for e in EMOTIONS) and all(rcounts.get(e, 0) >= 3 for e in EMOTIONS)
    regen_levels = None
    if regen_ok:
        regen_levels = {a: emopaper_from_means({e: rmean[e][a] for e in EMOTIONS}, own_comps[a], own_evr[a])
                        for a in PRIMARY_AGGS}
        add_to_store(store, norms_meta, "emopaper_regen", regen_levels, PRIMARY_AGGS, PC_LEVELS, want_raw)
        metrics["content_attenuation_regen"] = {a: content_attenuation(regen_levels, a) for a in PRIMARY_AGGS}
    else:
        print("[regen] WARNING: an emotion has <3 kept regen items — regen direction NOT built:",
              {e: rcounts.get(e, 0) for e in EMOTIONS})
    metrics["regen_keep_report"] = regen_report
    metrics["regen_kept_counts"] = {e: int(rcounts.get(e, 0)) for e in EMOTIONS}
    metrics["regen_built"] = bool(regen_ok)
    metrics["regen_primary_pc_level"] = "pc0"
    metrics["regen_pc_baseline"] = "persona-suppress own-response (exploratory; suppress-signature caveat)"

    # EITHER-JUDGE regen (review #3): un-thins the judge-sensitive hostile cell (haiku conservative). Stored as
    # a parallel candidate so Seg-10 inherits a usable hostile direction (not just a rebuild instruction).
    keep_regen_either, regen_either_report = load_keep(model_alias, "regen", keep_clarity, keep_intensity,
                                                       criterion="either")
    rmean_e, rcnt_e = group_means(cache, rg_items, rg_keys, lambda it: it["emotion"], PRIMARY_AGGS, n_layers,
                                  keep_ids=keep_regen_either)
    regen_either_levels = None
    if all(rcnt_e.get(e, 0) >= 3 for e in EMOTIONS):
        regen_either_levels = {a: emopaper_from_means({e: rmean_e[e][a] for e in EMOTIONS}, own_comps[a],
                                                      own_evr[a]) for a in PRIMARY_AGGS}
        add_to_store(store, norms_meta, "emopaper_regen_either", regen_either_levels, PRIMARY_AGGS, PC_LEVELS,
                     want_raw)
    metrics["regen_either_kept_counts"] = {e: int(rcnt_e.get(e, 0)) for e in EMOTIONS}
    metrics["regen_either_keep_report"] = regen_either_report

    # REGEN-MATCHED (review #4): own-response AND topic-controlled within-scenario direction (use either-judge
    # keep to maximize scenario completeness given the thin hostile cell). The cleanest own-response candidate.
    scen_regen, _ = group_means(cache, rg_items, rg_keys,
                                lambda it: (it["matched_set_id"], it["emotion"]) if it.get("block") == "matched"
                                else None, PRIMARY_AGGS, n_layers, keep_ids=keep_regen_either)
    regen_matched_levels, n_rm = {}, 0
    rm_ok = True
    for a in PRIMARY_AGGS:
        sm = {k: v[a] for k, v in scen_regen.items()}
        lv, n_rm = matched_from_scenmeans(sm, own_comps[a], own_evr[a])
        if lv is None:
            rm_ok = False
            break
        regen_matched_levels[a] = lv
    if rm_ok:
        add_to_store(store, norms_meta, "emopaper_regen_matched", regen_matched_levels, PRIMARY_AGGS, PC_LEVELS,
                     want_raw)
        metrics["regen_matched_n_scenarios"] = n_rm
    else:
        regen_matched_levels = None
        print("[regen-matched] no complete matched scenarios (even either-judge) — skipped")

    # ---------- geometry sanity + selection-bias diagnostics ----------
    metrics["geometry"] = geometry_sanity(emo_stories, persona_levels, regen_levels, matched_levels, n_layers,
                                          persona_centered=persona_centered, regen_either=regen_either_levels,
                                          regen_matched=regen_matched_levels)
    metrics["selection_diagnostics"] = selection_diagnostics(model_alias, keep_clarity, keep_intensity)

    # ---------- write ----------
    # full (gitignored, regenerable $0): every candidate × agg × pc level, raw + unit + extra aggregates.
    full_npz = OUT / f"directions_{model_alias}_full.npz"
    np.savez_compressed(full_npz, **store)
    # committed SLIM (the durable deliverable): unit-only, mean+median, the LEADING candidates. We commit
    # pc0+pcmod for the emotions-paper sweep paths and pc0 for matched/persona/regen (regen primary=pc0); the
    # risky large-k pc50 arm + raw arrays + last/prereply/eot extras stay in the gitignored full npz
    # (regenerable for $0 via build_directions.py). All 64 layers kept (the layer sweep is the point).
    # Committed SLIM (lean; .git already carries the regenerable full npz cost): the CANONICAL recipe outputs —
    # emopaper_stories (pc0+pcmod, all 6 emotions + axes incl. arousal_datadriven), persona_ownresp (pc0), and
    # the two leading own-response candidates emopaper_regen + emopaper_regen_matched (pc0); unit-only mean+median,
    # all 64 layers. Everything else (emopaper_matched, persona_centered, emopaper_regen_either, pc50, raw arrays,
    # last/prereply/eot extras) stays in the gitignored full npz, regenerable for $0 via build_directions.py
    # (the file_cache carries forward across segments; if it is ever lost, regenerating those is a GPU run).
    commit_pc = {"emopaper_stories": ("pc0", "pcmod"), "persona_ownresp": ("pc0",),
                 "emopaper_regen": ("pc0",), "emopaper_regen_matched": ("pc0",)}
    slim = {}
    for k, v in store.items():
        if not k.endswith("__unit"):
            continue
        prefix, name, agg, lvl, _ = k.split("__")
        if agg in PRIMARY_AGGS and lvl in commit_pc.get(prefix, ()):
            slim[k] = v
    slim_npz = OUT / f"directions_{model_alias}.npz"
    np.savez_compressed(slim_npz, **slim)
    (OUT / f"direction_norms_{model_alias}.json").write_text(json.dumps(norms_meta))
    (OUT / f"direction_metrics_{model_alias}.json").write_text(json.dumps(metrics, indent=2))
    print(f"\n[store] full {full_npz.name} {full_npz.stat().st_size/1e6:.1f}MB ({len(store)} arr) | "
          f"slim {slim_npz.name} {slim_npz.stat().st_size/1e6:.1f}MB ({len(slim)} arr, unit-only)")

    g = metrics["geometry"]
    print("\n=== RE-VALIDATION KEEP-RATES (per emotion, per path) ===")
    for path, rep in [("persona-exhibit", persona_report), ("regen-ownresp", regen_report)]:
        if not rep:
            continue
        print(f" {path}:")
        for e in EMOTIONS:
            if e in rep:
                r = rep[e]
                print(f"   {e:>11}: {r['kept']:>3}/{r['n']:<3} = {r['keep_rate']:.0%}"
                      + ("  <-- LOW" if r["keep_rate"] < 0.5 else ""))
    print(f"\nPCA top-2 var (stories mean pc0, midL): {g.get('pca_top2_stories_mean')} (→1 ⇒ collapse risk)")
    print(f"story-vs-persona cos (mid-band): {g.get('story_persona_cos_mean')}")
    print(f"story-vs-regen cos (mid-band): {g.get('story_regen_cos_mean')}")
    return metrics


if __name__ == "__main__":
    p = argparse.ArgumentParser()
    p.add_argument("--model", default="qwen3-32b")
    p.add_argument("--keep-clarity", type=int, default=4)
    p.add_argument("--keep-intensity", type=int, default=3)
    p.add_argument("--no-raw", action="store_true", help="store unit-only in the full npz too")
    args = p.parse_args()
    main(args.model, args.keep_clarity, args.keep_intensity, want_raw=not args.no_raw)

